def predict(triples: list[Triple]) -> str:
    """Generate a fluent sentence describing the given sports‑team triples."""
    if not triples:
        return ""
    # Use the subject of the first triple as the main entity.
    subject = triples[0].subject
    parts: list[str] = []
    for triple in triples:
        p, o = triple.predicate, triple.object
        # Simple phrasing rules for each predicate.
        if p == "numberOfMembers":
            phrase = f"{subject} has {o} members"
        elif p == "season":
            phrase = f"{subject} played in the {o} season"
        elif p == "league":
            phrase = f"{subject} competes in the {o} league"
        elif p == "manager":
            phrase = f"{subject} is managed by {o}"
        elif p == "ground":
            phrase = f"{subject} plays at {o}"
        elif p == "fullName":
            phrase = f"{subject}'s full name is {o}"
        elif p == "chairman":
            phrase = f"{subject}'s chairman is {o}"
        elif p == "location":
            phrase = f"{subject} is located in {o}"
        elif p == "owner":
            phrase = f"{subject}'s owner is {o}"
        elif p == "nickname":
            phrase = f"{subject}'s nickname is \"{o}\""
        elif p == "chairmanTitle":
            phrase = f"The chairman of {subject} holds the title {o}"
        elif p == "isPartOf":
            phrase = f"{subject} is part of {o}"
        elif p == "leader":
            phrase = f"The leader of {subject} is {o}"
        elif p == "part":
            phrase = f"{subject} includes {o}"
        elif p == "mayor":
            phrase = f"The mayor of {subject} is {o}"
        elif p == "champions":
            phrase = f"The champions of {subject} are {o}"
        elif p == "country":
            phrase = f"{subject} belongs to {o}"
        elif p == "club":
            phrase = f"{subject} plays for {o}"
        elif p == "capital":
            phrase = f"The capital of {subject} is {o}"
        elif p == "currency":
            phrase = f"The currency of {subject} is {o}"
        elif p == "demonym":
            phrase = f"The demonym of {subject} is {o}"
        elif p == "language":
            phrase = f"The language of {subject} is {o}"
        elif p == "leaderParty":
            phrase = f"The leader's party of {subject} is {o}"
        elif p == "officialLanguage":
            phrase = f"The official language of {subject} is {o}"
        elif p == "birthPlace":
            phrase = f"{subject} was born in {o}"
        elif p == "youthclub":
            phrase = f"{subject}'s youth club was {o}"
        elif p == "operator":
            phrase = f"The operator of {subject} is {o}"
        elif p == "tenant":
            phrase = f"The tenant of {subject} is {o}"
        elif p == "city":
            phrase = f"{subject} is in the city of {o}"
        elif p == "state":
            phrase = f"{subject} is in the state of {o}"
        else:
            phrase = f"{subject} has {p} {o}"
        parts.append(phrase)
    # Join with commas and finish with a period.
    return ", ".join(parts) + "."

